def view_content(uid, cont_id):
    # Guard clause: Check if user exists
    if uid not in USERS:
        return "Access Denied"

    # Guard clause: Check if content exists
    if cont_id not in CONTENT:
        return "Access Denied"

    user = USERS[uid]
